const t=JSON.parse('{"key":"v-82c8b0e0","path":"/MyNotes/%E9%9D%A2%E8%AF%95-MyBatis.html","title":"面试-Mybatis","lang":"zh-CN","frontmatter":{"icon":"/icon/streamline-stickies-color--face-id-1.svg","date":"2026-02-28T00:00:00.000Z","category":["面试"],"footer":"面试是检验，笔记是沉淀，成长是最终答案。","tag":["面试-Mybatis"],"description":"面试-Mybatis Mybatis缓存机制 问：Mybatis缓存机制 答：1. 一级缓存是MyBatis默认开启的缓存机制，它是指在同一个SqlSession内的缓存。当进行相同的查询时，如果该查询的结果已经在当前SqlSession的本地缓存中存在，则直接从缓存中获取结果，而不再去数据库查询。本地缓存的作用域是SqlSession，当SqlSession关闭时，本地缓存也会被清空。2. 二级缓存是指在SqlSessionFactory层面的缓存，它可以被多个SqlSession共享。当多个SqlSession执行相同的查询时，如果查询结果已经存在于二级缓存中，则直接从缓存中获取结果，而不会再去数据库查询。二级缓存的作用域是SqlSessionFactory，在整个应用的生命周期内有效。需要注意的是，二级缓存需要在MyBatis的配置文件中明确地配置开启。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/MyNotes/%E9%9D%A2%E8%AF%95-MyBatis.html"}],["meta",{"property":"og:site_name","content":"TenSoFlowBlog"}],["meta",{"property":"og:title","content":"面试-Mybatis"}],["meta",{"property":"og:description","content":"面试-Mybatis Mybatis缓存机制 问：Mybatis缓存机制 答：1. 一级缓存是MyBatis默认开启的缓存机制，它是指在同一个SqlSession内的缓存。当进行相同的查询时，如果该查询的结果已经在当前SqlSession的本地缓存中存在，则直接从缓存中获取结果，而不再去数据库查询。本地缓存的作用域是SqlSession，当SqlSession关闭时，本地缓存也会被清空。2. 二级缓存是指在SqlSessionFactory层面的缓存，它可以被多个SqlSession共享。当多个SqlSession执行相同的查询时，如果查询结果已经存在于二级缓存中，则直接从缓存中获取结果，而不会再去数据库查询。二级缓存的作用域是SqlSessionFactory，在整个应用的生命周期内有效。需要注意的是，二级缓存需要在MyBatis的配置文件中明确地配置开启。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"article:author","content":"TenSoFlow"}],["meta",{"property":"article:tag","content":"面试-Mybatis"}],["meta",{"property":"article:published_time","content":"2026-02-28T00:00:00.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"面试-Mybatis\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2026-02-28T00:00:00.000Z\\",\\"dateModified\\":null,\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"TenSoFlow\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":3,"title":"Mybatis缓存机制","slug":"mybatis缓存机制","link":"#mybatis缓存机制","children":[]},{"level":3,"title":"#{}和${}区别","slug":"和-区别","link":"#和-区别","children":[]}],"git":{"createdTime":null,"updatedTime":null,"contributors":[]},"readingTime":{"minutes":1.22,"words":367},"filePathRelative":"MyNotes/面试-MyBatis.md","localizedDate":"2026年2月28日","excerpt":"<h1> 面试-Mybatis</h1>\\n<h3> Mybatis缓存机制</h3>\\n<details class=\\"hint-container details\\"><summary><b style=\\"color:#bf3e73\\">问：Mybatis缓存机制</b></summary>\\n<p><b style=\\"color:#f19977\\">答：<br>1. 一级缓存是MyBatis默认开启的缓存机制，它是指在同一个SqlSession内的缓存。当进行相同的查询时，如果该查询的结果已经在当前SqlSession的本地缓存中存在，则直接从缓存中获取结果，而不再去数据库查询。本地缓存的作用域是SqlSession，当SqlSession关闭时，本地缓存也会被清空。<br>2. 二级缓存是指在SqlSessionFactory层面的缓存，它可以被多个SqlSession共享。当多个SqlSession执行相同的查询时，如果查询结果已经存在于二级缓存中，则直接从缓存中获取结果，而不会再去数据库查询。二级缓存的作用域是SqlSessionFactory，在整个应用的生命周期内有效。需要注意的是，二级缓存需要在MyBatis的配置文件中明确地配置开启。</b></p>\\n</details>","copyright":{"author":"TenSoFlow","license":"MIT"},"autoDesc":true}');export{t as data};
